import React, { type ComponentProps, type MouseEvent } from 'react'
import { useTranslation } from 'react-i18next'
import { trackEvent } from '@fs/zion-analytics'
import { useStatusOverlay, ActionChip } from '@fs/zion-ui'
import { copyToClipboard } from '@fs/zion-frontend-friends'

type Props = {
  /** The name of the analytics event to be tracked */
  analyticsEventName?: string | null
  copiedMessage?: string
  /** The value to copy to the clipboard. This can be used when a different value than what is shown needs to be copied. If it is not provided, the textContent of the children will be used as the value. */
  value: string
  /** Whether the ActionChip should be inline or not */
  inline?: boolean
  'aria-label'?: string
} & Omit<ComponentProps<typeof ActionChip>, 'label' | 'onClick'>

export default function ClickToCopy({
  value,
  copiedMessage,
  analyticsEventName = null,
  inline,
  'aria-label': ariaLabel,
  ...props
}: Props): JSX.Element {
  const showStatusOverlay = useStatusOverlay()
  const [t] = useTranslation()

  function copyValue(evt: MouseEvent<HTMLButtonElement>): void {
    evt.stopPropagation()

    copyToClipboard(value, 'text/plain', () => {
      if (analyticsEventName) {
        trackEvent({ event_name: analyticsEventName })
      }

      showStatusOverlay({
        message: copiedMessage || t('click-to-copy.person-id-copied.alert-message'),
        type: 'normal',
        transient: true,
      })
    })
  }

  return (
    <ActionChip
      inline={inline}
      data-testid="clickToCopy"
      {...props}
      label={value}
      aria-label={`${ariaLabel || value}, ${t('click-to-copy.click-to-copy-button.aria-label-suffix')}`}
      onClick={copyValue}
    />
  )
}
