import { PersonBlock, Skeleton } from '@fs/zion-ui'
import React from 'react'
import { type AvatarSize, type ComponentSize, type Orientation } from '../../types/personComponent'
import PortraitDetails from './PersonBlockPortraitDetails'
import LandscapeDetails from './PersonBlockLandscapeDetails'
import PrimaryNameSkeleton from './PrimaryNameSkeleton'

type Props = {
  componentSize: NonNullable<ComponentSize>
  inline: boolean | undefined
  centered: boolean | undefined
  avatarSize: AvatarSize
  noAvatar: boolean | undefined
  hasOverline: boolean | undefined
  orientation: Orientation | undefined
  hidePid: boolean | undefined
  disableTruncation: boolean | undefined
  hideLifespan: boolean | undefined
}
export default function PersonBlockSkeleton({
  componentSize,
  inline,
  centered,
  avatarSize,
  noAvatar,
  hasOverline,
  orientation,
  hidePid,
  disableTruncation,
  hideLifespan,
}: Props): JSX.Element {
  return (
    <div data-testid="person:loading-skeleton">
      <PersonBlock
        aria-hidden
        size={componentSize}
        inline={inline}
        centered={centered}
        avatarSize={avatarSize}
        noAvatar={noAvatar}
        overline={hasOverline ? <Skeleton.TypeSkeleton maxWidth={100} randomSeed={2} /> : undefined}
        name={<PrimaryNameSkeleton disableTruncation={disableTruncation} />}
        details={
          <>
            {orientation === 'portrait' ? (
              <PortraitDetails componentSize={componentSize} hidePid={hidePid} hideLifespan={hideLifespan} />
            ) : (
              <LandscapeDetails
                componentSize={componentSize}
                inline={inline}
                hidePid={hidePid}
                hideLifespan={hideLifespan}
              />
            )}
          </>
        }
        avatarProps={noAvatar ? undefined : { sex: 'unknown' }}
      />
    </div>
  )
}
