import { Skeleton } from '@fs/zion-ui'
import React from 'react'
import { css, cx } from '@linaria/core'
import { type ComponentSize } from '../../types/personComponent'
import { clickToCopyPidHeight, lgOrXlLifespanHeight, lifespanHeight } from './constants'

const personBlockDetailsLgOrXlCss = css`
  /* Height of lifespan vs height of ClickToCopy Pid */
  height: max(${lgOrXlLifespanHeight}, ${clickToCopyPidHeight});
  display: flex;
`

const personBlockDetailsDefaultCss = css`
  /* Height of lifespan vs height of ClickToCopy Pid */
  height: max(${lifespanHeight}, ${clickToCopyPidHeight});
  display: flex;
`

type Props = {
  componentSize: NonNullable<ComponentSize>
  inline: boolean | undefined
  hidePid: boolean | undefined
  hideLifespan: boolean | undefined
}

export default function LandscapeDetails({ componentSize, inline, hidePid, hideLifespan }: Props): JSX.Element | null {
  if (hidePid && !hideLifespan) {
    return <Skeleton.TypeSkeleton maxWidth={250} />
  }

  if (hidePid && hideLifespan) {
    return null
  }

  return (
    <div
      className={cx(
        (componentSize === 'lg' || componentSize === 'xl') && !inline
          ? personBlockDetailsLgOrXlCss
          : personBlockDetailsDefaultCss
      )}
    >
      <Skeleton.TypeSkeleton maxWidth={250} />
    </div>
  )
}
