import { Skeleton } from '@fs/zion-ui'
import React from 'react'
import { css } from '@linaria/core'
import { clickToCopyPidHeight, lifespanHeight } from './constants'

const listItemSecondaryTextCss = css`
  /* Height of lifespan vs height of ClickToCopy Pid*/
  height: max(${lifespanHeight}, ${clickToCopyPidHeight});
  display: flex;
`

const listItemSecondaryTextWithTagCss = css`
  /* Height of lifespan vs height of Tag*/
  height: max(${lifespanHeight}, 25px);
  display: flex;
`

type Props = {
  hasTag: boolean | undefined
  hidePid: boolean | undefined
  hideLifespan: boolean | undefined
}

export default function PersonListSecondaryText({ hidePid, hideLifespan, hasTag }: Props): JSX.Element | null {
  if (hidePid && !hideLifespan && !hasTag) return <Skeleton.TypeSkeleton maxWidth={240} randomSeed={1} />

  if (hasTag || !hideLifespan || !hidePid) {
    return (
      <div className={hasTag ? listItemSecondaryTextWithTagCss : listItemSecondaryTextCss}>
        <Skeleton.TypeSkeleton maxWidth={hidePid && hideLifespan ? 75 : 240} randomSeed={1} />
      </div>
    )
  }
  return null
}
