import { Ellipsis, Skeleton } from '@fs/zion-ui'
import React from 'react'

type Props = {
  disableTruncation?: boolean
}

export default function PrimaryNameSkeleton({ disableTruncation }: Props): JSX.Element {
  const PrimaryTextWrapper = disableTruncation ? 'span' : Ellipsis
  return (
    <PrimaryTextWrapper>
      <Skeleton.TypeSkeleton maxWidth={250} randomSeed={3} />
    </PrimaryTextWrapper>
  )
}
