import { useEffect, useRef, useState } from 'react'
import { type PID } from '@fs/zion-tree-types'
import { subscribeToPersonObj } from './PersonService'
import { type LoadingPerson, type PersonSize, type PersonForSize, type UnknownPerson, type Placeholder } from './types'

/**
 * @description - the hook to use the person data service to populate the personObj
 * @param {string} pid - a person id to get the person object for
 * @param {string} size - the size of the person (card, summary, full)
 * @param {object} placeholder - when this is defined, we will return immediately an object that has all the props from the placeholder along with a 'loading' prop. It will be overridden by the person when the useEffect finishes, but is intended to be used for when there is some person data available that you would like to display to the user immediately but still desire to show a loading state indicating that the information could be updated.
 * @param {boolean} preferCache - when this is set to true, if the person is in the cache, the request will not be made to fetch the person again
 * @param {boolean} ignoreCache - when this is set to true, the request will be made to fetch the person again, regardless of the cache
 * @returns {object} the person object.
 */

function usePerson<S extends PersonSize, T extends Placeholder>(
  pid: PID | undefined,
  size: S,
  placeholder: T,
  preferCache?: boolean,
  ignoreCache?: boolean
): PersonForSize<S> | UnknownPerson | LoadingPerson<T>
function usePerson<S extends PersonSize, T extends Placeholder>(
  pid: PID | undefined,
  size: S,
  placeholder: T | undefined,
  preferCache?: boolean,
  ignoreCache?: boolean
): PersonForSize<S> | UnknownPerson | LoadingPerson<T> | undefined
function usePerson<S extends PersonSize>(
  pid: PID | undefined,
  size?: S,
  placeholder?: undefined,
  preferCache?: boolean,
  ignoreCache?: boolean
): PersonForSize<S> | UnknownPerson | undefined
function usePerson<S extends PersonSize, T extends Placeholder>(
  pid: PID | undefined,
  size?: S,
  placeholder?: T,
  preferCache?: boolean,
  ignoreCache?: boolean
): PersonForSize<S> | UnknownPerson | LoadingPerson<T> | undefined {
  const loading = placeholder ? ({ ...placeholder, loading: true } satisfies LoadingPerson<T>) : undefined
  const loadingRef = useRef(loading)
  loadingRef.current = loading
  const [personObj, setPersonObj] = useState<PersonForSize<S> | UnknownPerson | LoadingPerson<T> | undefined>(loading)

  useEffect(() => {
    // TODO 'undefined' string is here for legacy reasons, we should remove it in the next major bump
    if (!pid || pid === ('undefined' as never)) {
      return undefined
    }
    setPersonObj((prev) => (prev?.id === pid ? prev : loadingRef.current))
    // this is from the service
    const subscription = subscribeToPersonObj(pid, size, (person) => setPersonObj(person), preferCache, ignoreCache)
    return function cleanup() {
      subscription.remove()
    }
  }, [pid, size, preferCache, ignoreCache])

  // Prevent returning stale person data when PID changes before useEffect runs
  if (personObj && 'id' in personObj && personObj.id !== pid) {
    return loading
  }

  return personObj
}

export default usePerson
