import { Grid, Skeleton } from '@fs/zion-ui'
import React from 'react'
import { css, cx } from '@linaria/core'
import { type ComponentSize } from '../../types/personComponent'
import { clickToCopyPidHeight, lgOrXlLifespanHeight, lifespanHeight } from './constants'

const justifyCenterCss = css`
  justify-content: center;
`

const pidSkeletonCss = css`
  height: ${clickToCopyPidHeight};
  display: flex;
`

const lifespanSkeletonCss = css`
  height: ${lifespanHeight};
  display: flex;
`

const lgOrXlLifespanSkeletonCss = css`
  height: ${lgOrXlLifespanHeight};
  display: flex;
`

type PortraitDetailsProps = {
  componentSize: NonNullable<ComponentSize>
  hidePid: boolean | undefined
  hideLifespan: boolean | undefined
}

export default function PortraitDetails({ componentSize, hidePid, hideLifespan }: PortraitDetailsProps): JSX.Element {
  return (
    <Grid gutters="pico">
      {!hideLifespan && (
        <div
          className={cx(
            justifyCenterCss,
            componentSize === 'xl' || componentSize === 'lg' ? lgOrXlLifespanSkeletonCss : lifespanSkeletonCss
          )}
        >
          <Skeleton.TypeSkeleton maxWidth={150} />
        </div>
      )}
      {!hidePid && (
        <div className={cx(justifyCenterCss, pidSkeletonCss)}>
          <Skeleton.TypeSkeleton maxWidth={100} />
        </div>
      )}
    </Grid>
  )
}
