import { ListItem, Skeleton } from '@fs/zion-ui'
import React from 'react'
import PersonListSecondaryText from './PersonListSecondaryText'
import PrimaryNameSkeleton from './PrimaryNameSkeleton'

type Props = {
  noAvatar: boolean | undefined
  hasOverline: boolean | undefined
  hasTag: boolean | undefined
  hasEndElement: boolean | undefined
  dense: boolean | undefined
  disableTruncation: boolean | undefined
  hidePid: boolean | undefined
  hideLifespan: boolean | undefined
}

export default function PersonListSkeleton({
  noAvatar,
  hasOverline,
  hasTag,
  hasEndElement,
  dense,
  disableTruncation,
  hidePid,
  hideLifespan,
}: Props): JSX.Element {
  return (
    <ListItem
      aria-hidden
      startElement={noAvatar ? undefined : <Skeleton.Avatar size={dense ? 'xs' : 'sm'} />}
      overline={hasOverline ? <Skeleton.TypeSkeleton maxWidth={100} randomSeed={2} /> : undefined}
      primaryText={<PrimaryNameSkeleton disableTruncation={disableTruncation} />}
      secondaryText={<PersonListSecondaryText hidePid={hidePid} hideLifespan={hideLifespan} hasTag={hasTag} />}
      endElement={hasEndElement ? <Skeleton.Icon /> : undefined}
      as="li"
      dense={dense}
      data-testid="person:loading-skeleton"
    />
  )
}
