import React from 'react'
import type { AvatarSize, ComponentSize, Orientation } from '../../types/personComponent'
import PersonListSkeleton from './PersonListSkeleton'
import PersonBlockSkeleton from './PersonBlockSkeleton'

type Props = {
  /** Increment/Decrement the size of the avatar by a t-shirt size. */
  avatarSize: AvatarSize
  /** The size of the avatar or placeholder and name text. */
  componentSize: NonNullable<ComponentSize>
  /** Basically if we are in portrait orientation. */
  centered?: boolean
  orientation?: Orientation
  asListItem?: boolean
  noAvatar?: boolean
  inline?: boolean
  dense?: boolean
  hasEndElement?: boolean
  hasOverline?: boolean
  disableTruncation?: boolean
  hasTag?: boolean
  hidePid?: boolean
  hideLifespan?: boolean
}

export default function PersonSkeleton({
  avatarSize,
  componentSize,
  centered,
  orientation,
  asListItem,
  noAvatar,
  inline,
  dense,
  hasEndElement,
  hasOverline,
  disableTruncation,
  hasTag,
  hidePid,
  hideLifespan,
}: Props): JSX.Element {
  if (asListItem) {
    return (
      <PersonListSkeleton
        noAvatar={noAvatar}
        hasOverline={hasOverline}
        hasTag={hasTag}
        hasEndElement={hasEndElement}
        dense={dense}
        disableTruncation={disableTruncation}
        hidePid={hidePid}
        hideLifespan={hideLifespan}
      />
    )
  }

  return (
    <PersonBlockSkeleton
      componentSize={componentSize}
      inline={inline}
      centered={centered}
      avatarSize={avatarSize}
      noAvatar={noAvatar}
      hasOverline={hasOverline}
      orientation={orientation}
      hidePid={hidePid}
      disableTruncation={disableTruncation}
      hideLifespan={hideLifespan}
    />
  )
}
